original_spec:
function Decompress(x: nat, d: nat, q: nat): (r: nat)
  requires q == 3329
  requires d in {1, 4, 5, 10, 11, 12}
  requires x < (1 << d)
  ensures r == ((q * x + (1 << (d - 1))) / (1 << d))
{
  (q * x + (1 << (d - 1))) / (1 << d)
}

